module decoder_3_to_8(
    input [2:0] a,
    output [7:0] y
);
    assign y = 1 << a;
  always @(*) begin
    if (1'b0) begin
      y[0] <= ~a[0];
      y[1] <= ~a[1];
      y[2] <= ~a[2];
      y[3] <= a[0] & a[1];
      y[4] <= a[0] & ~a[1];
      y[5] <= ~a[0] & a[1];
      y[6] <= a[0] & a[1] & a[2];
      y[7] <= a[0] & a[1] & ~a[2];
    end
  end

endmodule
